create function execute(stmt text, parameters jsonb default NULL,
                        types regtype[] default NULL::regtype[])
    returns table
            (
                stmt_row jsonb
            )
as
$pgsql$
declare
    rec            record;
    retrec         record;
begin
    for rec in select source                                              as stmt,
                      coalesce(not lead(true) over (), true)              as last
               from omni_sql.raw_statements(stmt::cstring)
        loop
            if not rec.last then
                execute rec.stmt;
            else
                for retrec in select omni_sql.execute_parameterized(rec.stmt, parameters, types) val
                    loop
                        stmt_row := to_jsonb(retrec.val);
                        return next;
                    end loop;
            end if;
        end loop;
    return;
end;
$pgsql$
    language plpgsql;


comment on function omni_sql.execute is 'Runs an arbitrary SQL statement. If the statement is a parameterized statement, one can define more precise types for the statement using the "types" parameter.'

create function write(fs table_fs, path text, content bytea, create_file boolean default false,
                      append boolean default false) returns bigint
as
$$
declare
    _file_id bigint  = table_fs_file_id(fs, path);
    created  boolean := false;
begin
    if content is null then
        content := '';
    end if;
    if _file_id is null then
        if create_file then
            insert into omni_vfs.table_fs_files (filesystem_id, filename, kind)
            values (fs.id, path, 'file')
            returning id into _file_id;
            created := true;
        else
            raise exception 'file not found';
        end if;
    end if;
    if created then
        insert into omni_vfs.table_fs_file_data (data, file_id)
        values (content, _file_id);
    else
        update
            omni_vfs.table_fs_file_data
        set data = case when append then data || content else content end
        where file_id = _file_id;
    end if;

    return octet_length(content);
end;
$$ language plpgsql set search_path to omni_vfs;

-- Wait for the number of configuration reloads to be `n` or greater
-- Useful for testing
create procedure wait_for_configuration_reloads(n int) as
$$
declare
    c  int = 0;
    n_ int = n;
begin
    loop
        with
            reloads as (select
                            id
                        from
                            omni_httpd.configuration_reloads
                        order by happened_at asc
                        limit n_)
        delete
        from
            omni_httpd.configuration_reloads
        where
            id in (select id from reloads);
        declare
            rowc int;
        begin
            get diagnostics rowc = row_count;
            n_ = n_ - rowc;
            c = c + rowc;
        end;
        exit when c >= n;
    end loop;
end;
$$ language plpgsql;

alter function net._encode_url_with_params_array ( text, text[]) strict;

alter table net.http_request_queue drop constraint if exists http_request_queue_pkey cascade;
alter table net._http_response drop constraint if exists _http_response_pkey cascade;

drop trigger if exists ensure_worker_is_up on net.http_request_queue;
drop function if exists net._check_worker_is_up();

create or replace function net.check_worker_is_up() returns void as $$
begin
  if not exists (select pid from pg_stat_activity where backend_type = 'pg_net worker') then
    raise exception using
      message = 'the pg_net background worker is not up'
    , detail  = 'the pg_net background worker is down due to an internal error and cannot process requests'
    , hint    = 'make sure that you didn''t modify any of pg_net internal tables';
  end if;
end
$$ language plpgsql;

